INSERT INTO drug_knowledge (tenant_id, drug_code, generic_name, trade_name, pinyin, pinyin_short, dosage_form, specification, manufacturer, category, otc_type, indication, dosage, contraindication, precaution, adverse_reaction, interaction, pregnancy_category, is_antibiotics, is_psychotropic, is_narcotic, medical_insurance, storage_condition, valid_period, reference_price) VALUES
