(0, 'DK0143', '小儿消积止咳口服液', '小儿消积止咳', 'xiaoerxiaojizhi', 'xexjzk', '口服液', '10ml*6支', '鲁南厚普制药有限公司', '儿科', 'OTC甲', '清热理肺，消积止咳。用于小儿食积咳嗽，症见咳嗽、喉间痰鸣、腹胀口臭', '口服，1~2岁一次5ml，3~5岁一次10ml，6岁以上一次15ml，一日3次', '对本品过敏者禁用', '脾胃虚寒者慎用', '偶见腹泻', NULL, 'B', 0, 0, 0, '甲', '密封保存', 24, 25.00),
