(0, 'DK0150', '赖氨酸磷酸氢钙颗粒', '盖笛欣', 'laiansuanlingsuanqing', 'laslsq', '颗粒剂', '5g*9袋', '南京海辰药业股份有限公司', '儿科', 'OTC甲', '用于促进幼儿正常生长发育，以及儿童及孕妇补充钙质', '口服，婴幼儿一次半袋，儿童一次1袋，一日1次', '高钙血症者禁用', '肾功能不全者慎用', '偶见便秘、胃肠不适', '不宜与四环素类药物同服', 'A', 0, 0, 0, '甲', '密封防潮', 24, 22.00);
